import org.apache.commons.collections.keyvalue.MultiKey;
import java.io.*;
import java.util.*;

import static org.junit.Assert.*;

public class StepDefs {

    private Object sysKey;
    private MultiKey mk1;
    private Map<Object, Object> map1;
    private Object value1 = "value1";
    private Object sysKey2;
    private MultiKey mk2;
    private Map<Object, Object> map2;

    @Given("a key object {string} with a hash code that changes after serialization")
    public void a_key_object_with_a_hash_code_that_changes_after_serialization(String keyName) {
        // Create a key with hash code that changes after serialization
        sysKey = new SystemHashCodeSimulatingKey("test");
        assertEquals(1, sysKey.hashCode()); // initial hash code
    }

    @Given("a MultiKey {string} created with {string}")
    public void a_multikey_created_with(String mkName, String keyName) {
        mk1 = new MultiKey("ONE", sysKey); // Using "ONE" as a simple key
    }

    @Given("a Map {string} containing {string} mapped to {string}")
    public void a_map_containing_mapped_to(String mapName, String mkName, String valueName) {
        map1 = new HashMap<>();
        map1.put(mk1, value1);
    }

    @When("{string} is serialized and deserialized to {string}")
    public void map_is_serialized_and_deserialized_to(String map1Name, String map2Name) throws IOException, ClassNotFoundException {
        // serialize
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        ObjectOutputStream out = new ObjectOutputStream(baos);
        out.writeObject(sysKey);
        out.writeObject(map1);
        out.close();

        // deserialize
        ByteArrayInputStream bais = new ByteArrayInputStream(baos.toByteArray());
        ObjectInputStream in = new ObjectInputStream(bais);
        sysKey2 = in.readObject(); // simulate deserialization in another process
        map2 = (Map<Object, Object>) in.readObject();
        in.close();
    }

    @When("{string} is retrieved from the deserialized stream as {string}")
    public void syskey_is_retrieved_from_the_deserialized_stream_as(String originalKeyName, String newKeyName) {
        // This step is handled in the previous step
        assertNotNull(sysKey2);
    }

    @When("a new MultiKey {string} is created with {string}")
    public void a_new_multikey_is_created_with(String mk2Name, String sysKeyName) {
        mk2 = new MultiKey("ONE", sysKey2);
    }

    @Then("{string} should contain {string}")
    public void map_should_contain(String map2Name, String mk2Name) {
        assertTrue(map2.containsKey(mk2));
    }

    @Then("getting {string} from {string} should return {string}")
    public void getting_mk2_from_map2_should_return_value1(String mk2Name, String map2Name, String valueName) {
        Object result = map2.get(mk2);
        assertEquals(value1, result);
    }

    // Helper class similar to the one in the original test
    static class SystemHashCodeSimulatingKey implements Serializable {
        private static final long serialVersionUID = 1L;
        private final String name;
        private int hashCode = 1;

        public SystemHashCodeSimulatingKey(String name) {
            this.name = name;
        }

        public boolean equals(Object obj) {
            return obj instanceof SystemHashCodeSimulatingKey
                && name.equals(((SystemHashCodeSimulatingKey)obj).name);
        }

        public int hashCode() {
            return hashCode;
        }

        private void readObject(ObjectInputStream in) throws IOException, ClassNotFoundException {
            in.defaultReadObject();
            this.hashCode = 2; // simulate different hashCode after deserialization in another process
        }
    }
}

